79	// Get all running agents from teams config files
80	function getRunningAgents() {
81	  const agents = [];
82	  const descriptions = loadDescriptions();
83	
84	  if (!fs.existsSync(TEAMS_DIR)) return agents;
85	
86	  const teamDirs = fs.readdirSync(TEAMS_DIR);
87	
88	  for (const teamName of teamDirs) {
89	    const teamConfigPath = path.join(TEAMS_DIR, teamName, 'config.json');
90	    try {
91	      const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));
92	
93	      if (config.members && config.members.length > 0) {
94	        // Detect if claude is running in Terminal for this team
95	        const terminalOpen = checkClaudeTerminalProcess(teamName);
96	
97	        for (const member of config.members) {
98	          const agentId = member.agentId;
99	
100	          // Lookup description case-insensitively
101	          let description = '';
102	          const descKey = lookupDescriptionKey(descriptions, member.name);
103	          if (descKey) {
104	            description = descriptions[descKey];
105	          } else if (KNOWN_AGENT_TYPES.includes(member.agentType)) {
106	            const typeDescKey = lookupDescriptionKey(descriptions, member.agentType);
107	            if (typeDescKey) description = descriptions[typeDescKey];
108	          }
109	          // Fall back to the team description
110	          if (!description && config.description) {
111	            description = config.description;
112	          }
113	
114	          // Check PID from wake-spawned background process
115	          const pid = loadPid(`${teamName}.pid`);
116	          const processAlive = pid && checkPidAlive(pid);
117	
118	          // Determine status: terminal open vs background process vs disconnected
119	          let sessionActive = processAlive || terminalOpen;
120	          let statusDetail = 'Not connected';
121	          if (terminalOpen && processAlive) {
122	            statusDetail = 'Answering — active session';
123	          } else if (terminalOpen) {
124	            statusDetail = 'Idle — Terminal open, awaiting input';
125	          } else if (processAlive) {
126	            statusDetail = 'Answering — background process';
127	          }
128	
129	          agents.push({
130	            id: agentId,
131	            name: member.name,
132	            teamName,
133	            type: member.agentType || 'general-purpose',
134	            description: description || '',
135	            sessionActive,
136	            statusDetail,
137	            processAlive,
138	            isLaunched: terminalOpen
139	          });
140	        }
141	      }
142	    } catch {
143	      // Skip invalid config files
144	    }
145	  }
146	
147	  return agents;
148	}
