189	// Build environment from user settings
190	function buildEnvScript() {
191	  let settingsEnv = {};
192	  try {
193	    const settingsPath = path.join(process.env.HOME, '.claude', 'settings.json');
194	    const settings = JSON.parse(fs.readFileSync(settingsPath, 'utf8'));
195	    settingsEnv = settings.env || {};
196	  } catch (e) {
197	    console.error('Could not read settings.json:', e.message);
198	  }
199	
200	  return {
201	    CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS: settingsEnv.CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS || '1',
202	    ANTHROPIC_BASE_URL: settingsEnv.ANTHROPIC_BASE_URL || '',
203	    ANTHROPIC_AUTH_TOKEN: settingsEnv.ANTHROPIC_AUTH_TOKEN || '',
204	    ANTHROPIC_API_KEY: settingsEnv.ANTHROPIC_API_KEY || '',
205	    ANTHROPIC_MODEL: settingsEnv.ANTHROPIC_MODEL || '',
