210	// Check if Claude CLI works (detects context management incompatibility)
211	let claudeCompatible = null; // null = not yet checked, boolean = cached
212	
213	function checkClaudeCompatibility() {
214	  if (claudeCompatible !== null) return claudeCompatible;
215	  const env = buildEnvScript();
216	  try {
217	    execSync(`"${env.CLAUDE_BIN}" --version`, { stdio: 'pipe' });
218	    // Try a quick API call to see if context management works
219	    execSync(
220	      `CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS='${env.CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS}' ` +
221	      `ANTHROPIC_BASE_URL='${env.ANTHROPIC_BASE_URL}' ` +
222	      `ANTHROPIC_AUTH_TOKEN='${env.ANTHROPIC_AUTH_TOKEN}' ` +
223	      `ANTHROPIC_API_KEY='${env.ANTHROPIC_API_KEY}' ` +
224	      `ANTHROPIC_MODEL='${env.ANTHROPIC_MODEL}' ` +
225	      `CLAUDECODE='' "${env.CLAUDE_BIN}" --print -p "hi" 2>&1`,
226	      { stdio: 'pipe', timeout: 15000 }
227	    );
228	    claudeCompatible = true;
229	    return true;
230	  } catch (e) {
231	    claudeCompatible = false;
232	    return false;
233	  }
234	}
