261	// Spawn a detached background claude process
262	function spawnBackgroundProcess(name, cmd) {
263	  const env = buildEnvScript();
264	  const logFile = path.join(__dirname, `logs/${name}-${Date.now()}.log`);
265	  const logsDir = path.join(__dirname, 'logs');
266	  if (!fs.existsSync(logsDir)) fs.mkdirSync(logsDir, { recursive: true });
267	
268	  const parts = parseCliArgs(cmd);
269	
270	  // Build a clean environment — omit CLAUDECODE to prevent nested-session rejection
271	  const cleanEnv = {
272	    ...process.env,
273	    CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS: env.CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS,
274	    ANTHROPIC_BASE_URL: env.ANTHROPIC_BASE_URL,
275	    ANTHROPIC_AUTH_TOKEN: env.ANTHROPIC_AUTH_TOKEN,
276	    ANTHROPIC_API_KEY: env.ANTHROPIC_API_KEY,
277	    ANTHROPIC_MODEL: env.ANTHROPIC_MODEL
278	  };
279	  delete cleanEnv.CLAUDECODE;
280	  delete cleanEnv.CLAUDE_CODE_SSE_PORT;
281	  delete cleanEnv.CLAUDE_CODE_ENTRYPOINT;
282	
283	  try {
284	    const child = spawn(env.CLAUDE_BIN, parts, {
285	      detached: true,
286	      stdio: ['ignore', 'pipe', 'pipe'],
287	      env: cleanEnv
288	    });
289	
290	    const logStream = fs.createWriteStream(logFile, { flags: 'a' });
291	    child.stdout.pipe(logStream);
292	    child.stderr.pipe(logStream);
293	
294	    child.unref();
295	    return { pid: child.pid, logFile };
296	  } catch (e) {
297	    console.error('Spawn failed:', e.message);
298	    return { pid: null, logFile, error: e.message };
299	  }
300	}
