396	// API: Spawn agent
397	// Since OpenRouter doesn't support Claude CLI context management,
398	// this creates a registered agent entry that users can manage from the dashboard.
399	// Status shows as "registered" — users can resume the session manually.
400	app.post('/api/spawn', (req, res) => {
401	  try {
402	    const { name, role, prompt, description } = req.body;
403	    const fullPrompt = prompt || `${name} is a ${role} agent.`;
404	
405	    const safeName = name.toLowerCase().replace(/[^a-z0-9]/g, '-');
406	    const teamName = `agent-${safeName}-${Date.now()}`;
407	    const backgroundId = `spawn-${safeName}-${Date.now()}`;
408	
409	    const canSpawn = checkClaudeCompatibility();
410	    let logFile = null;
411	    let pid = null;
412	
413	    if (canSpawn) {
414	      // Build the claude command
415	      let cmd;
416	      if (name.toLowerCase() === 'trevor' || role === 'manager' || role === 'trevor') {
417	        cmd = `--agent=trevor "${fullPrompt.replace(/"/g, '\\"')}"`;
418	      } else {
419	        cmd = `"${fullPrompt.replace(/"/g, '\\"')}"`;
420	      }
421	
422	      const result = spawnBackgroundProcess(backgroundId, cmd);
423	      pid = result.pid;
424	      logFile = result.logFile;
425	    }
426	
427	    if (pid) savePid(`${teamName}.pid`, pid);
428	
429	    // Save description
430	    if (description) {
431	      const descriptions = loadDescriptions();
432	      descriptions[name] = description;
433	      saveDescriptions(descriptions);
434	    }
435	
436	    // Create team entry so the dashboard can discover this agent
437	    const teamDir = path.join(TEAMS_DIR, teamName);
438	    const taskListDir = path.join(CLAUDE_DIR, 'tasks', teamName);
439	
440	    fs.mkdirSync(teamDir, { recursive: true });
441	    fs.mkdirSync(taskListDir, { recursive: true });
442	
443	    const teamConfig = {
444	      description: description || `${name} — ${role} agent`,
445	      leaderSessionId: null,
446	      createdAt: Date.now(),
447	      backgroundId,
448	      members: [{
449	        agentId: `agent-${safeName}`,
450	        name,
451	        agentType: role || 'general-purpose',
452	        backgroundId
453	      }]
454	    };
455	    fs.writeFileSync(
456	      path.join(teamDir, 'config.json'),
457	      JSON.stringify(teamConfig, null, 2)
458	    );
459	
460	    res.json({
461	      success: true,
462	      message: canSpawn
463	        ? `Agent "${name}" spawned in background`
464	        : `Agent "${name}" registered (OpenRouter — resume manually)`,
465	      name,
466	      teamName,
467	      logFile,
468	      canSpawn,
469	      resumeCommand: canSpawn ? null : `claude -r ${teamName}`
470	    });
471	  } catch (err) {
472	    res.status(500).json({ success: false, error: err.message });
473	  }
474	});
