511	// Open a new Terminal.app tab and run a command via inline osascript
512	// No intermediate files — command is passed directly in the AppleScript string
513	// Base64 encodes the script to avoid all shell quoting issues; deletes before execution
514	function openTerminalTab(title, command) {
515	  const safeTitle = title
516	    .replace(/\\/g, '\\\\')
517	    .replace(/"/g, '\\"');
518	
519	  // Escape the command for AppleScript string literals
520	  // Must handle: backslashes (first), double-quotes, dollar signs (AppleScript variable prefix)
521	  const safeCommand = command
522	    .replace(/\\/g, '\\\\')
523	    .replace(/"/g, '\\"')
524	    .replace(/\$/g, '\\$');
525	
526	  const appleScript = [
527	    `tell application "Terminal"`,
528	    `    do script "${safeCommand}"`,
529	    `    tell window 1 to set custom title to "${safeTitle}"`,
530	    `    tell window 1 to set title displays custom title to true`,
531	    `    tell window 1 to set miniaturized to true`,
532	    `end tell`
533	  ].join('\n');
534	
535	  // Base64 encode to bypass all shell quoting issues
536	  const b64 = Buffer.from(appleScript, 'utf8').toString('base64');
537	
538	  try {
539	    execSync(`printf '%s' ${b64} | base64 --decode | osascript -`, { stdio: 'pipe', timeout: 10000 });
540	    return true;
541	  } catch (e) {
542	    console.error(`Failed to open Terminal for ${title}: ${e.message}`);
543	    return false;
544	  }
545	}
