582	// API: Generate launch script that opens all agents in Terminal.app
583	app.get('/api/launch-script', (req, res) => {
584	  const agents = getRunningAgents();
585	  if (agents.length === 0) {
586	    return res.status(204).send('No agents to launch');
587	  }
588	
589	  const claudePath = path.join(process.env.HOME, '.local', 'bin', 'claude');
590	
591	  let script = `#!/bin/bash\n# Agent Office — Launch All Agents\n`;
592	  script += `cd "${__dirname}"\n`;
593	  script += `export CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS=1\n\n`;
594	
595	  agents.forEach((agent) => {
