// No intermediate files — command is passed directly in the AppleScript string
// Base64 encodes the script to avoid all shell quoting issues
function openTerminalTab(title, command) {
  const safeTitle = title
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"');

  const projectDir = __dirname;
  // Build a safe command string with cd prefix, avoiding shell injection
  const safeCommand = command
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"')
    .replace(/'/g, "'\"'\"'");

  const cmdWithCd = `cd '${projectDir}' && ${command}`;

